import React, { Fragment , useState} from 'react';
import PropTypes from 'prop-types';
import IconButton from '@material-ui/core/IconButton';
import MoreVertIcon from '@material-ui/icons/MoreVert';
import { makeStyles,
  ListItem,
  List,
  Box} from '@material-ui/core';
import ButtonLink from './ButtonLink';
import useWindowSize from '../utils/useWindowSize';

const BREAKPOINT = 640;

const useStyles = makeStyles((theme) => ({
  root: {
    textAlign: 'left',
    position: 'fixed',
    width: '100%',
    background: 'white',
    borderBottom: '1px solid #ddd',
    '& *': {
      textDecoration: 'none'
    },
    '& a.logo button': {
      fontSize: '20px',
      'paddingRight': '20px'
    }
  },
  spacer: {
    height: '40px'
  }
}));

const PopMenu = ({show, items}) => show ?
  <List>
    {items.map(item =>
      <ListItem button><ButtonLink to={item.url}>{item.title}</ButtonLink></ListItem>)}
  </List> : false;

const TopMenu = ({show, items}) => show ?
  <Fragment>
    {items.map(item => <ButtonLink to={item.url}>{item.title}</ButtonLink>)}
  </Fragment> : false;

const Logo = () => (<ButtonLink className='logo'>Ofir <b> Yaron</b></ButtonLink>);

const NavBar = ({menuItems}) => {
  const classes = useStyles();
  const [open, setOpen] = useState(false);
  const size = useWindowSize();

  const toggleOpen = () => {
    setOpen(!open);
  };

  return (<>
    <nav className={classes.root}>
    <Box display='flex'>
      <Box flexGrow={1}>
        <Logo className={'logo'}/>
        <TopMenu items={menuItems} show={(size.width > BREAKPOINT)} />
      </Box>

      { (size.width <= BREAKPOINT) ?
      <Box justifyContent={''}>
        <IconButton onClick={toggleOpen}><MoreVertIcon/></IconButton>
      </Box> : false }

    </Box>
    <Box>
      <Fragment>
        <Box flexDirection='row-reverse'>
        </Box>
        <PopMenu items={menuItems} show={open}/>
      </Fragment>
    </Box>
  </nav>
    <div className={classes.spacer} />
    </>);
};

NavBar.propTypes = {
  menuitem: PropTypes.array
};

export default NavBar;
