import React from 'react';
import NavBar from '../NavBar';
import {
  BrowserRouter as Router,
  Switch,
  Route
} from 'react-router-dom';

const menuItems = [
  {title: 'Home', url: '/'},
  {title: 'About', url: '/about'},
  {title: 'Contact Me', url: '/contact'}
];


export default function WebsiteRouter() {
  return (
    <Router>
      <div>
        <NavBar menuItems={menuItems}/>

        <Switch>
          <Route path="/about">
            <About />
          </Route>
          <Route path="/contact">
            <Users />
          </Route>
          <Route path="/">
            <Home />
          </Route>
        </Switch>
      </div>
    </Router>
  );
}

function Home() {
  return <h2>Home</h2>;
}

function About() {
  return <h2>About</h2>;
}

function Users() {
  return <h2>Contact Me</h2>;
}
